def standardize_model_name(model_name: str, is_completion: bool = False) -> str:
    """Map fine-tuned and versioned OpenAI model names to known price entries."""
    model_name = model_name.lower()

    if model_name.startswith("ft:"):
        model_name = model_name.split(":")[1]
    elif ":ft-" in model_name:
        model_name = model_name.split(":")[0]

    if model_name.startswith("gpt-4-32k"):
        model_name = "gpt-4-32k"
    elif model_name.startswith("gpt-4"):
        model_name = "gpt-4"
    elif model_name.startswith("gpt-3.5-turbo"):
        model_name = "gpt-3.5-turbo"

    if is_completion and model_name.startswith("gpt-4"):
        return model_name + "-completion"
    return model_name


