from langchain.callbacks.openai_info import (
    OpenAICallbackHandler,
    get_openai_model_cost_per_1k_tokens,
)
from langchain.schema import LLMResult


def test_get_openai_model_cost_per_1k_tokens_with_legacy_finetuned_model() -> None:
    """Legacy fine-tuned completion models should reuse their base-model pricing."""
    assert get_openai_model_cost_per_1k_tokens("davinci:ft-personal-2023-05-23-17-58-42") == 0.02


def test_get_openai_model_cost_per_1k_tokens_with_ft_prefix_model() -> None:
    """Newer fine-tuned model names should map back to their base-model pricing."""
    assert (
        get_openai_model_cost_per_1k_tokens("ft:gpt-3.5-turbo-0613:org::abc123")
        == 0.002
    )


def test_openai_callback_tracks_usage_for_finetuned_model() -> None:
    """The callback should account for usage instead of erroring on fine-tuned names."""
    handler = OpenAICallbackHandler()
    response = LLMResult(
        generations=[],
        llm_output={
            "token_usage": {
                "prompt_tokens": 100,
                "completion_tokens": 25,
                "total_tokens": 125,
            },
            "model_name": "ada:ft-personal-2023-05-23-17-58-42",
        },
    )

    handler.on_llm_end(response)

